const statusName = (columns: RelayColumn[], status: string): string =>
  columns.find((column) => column.id === status)?.name ?? status;

const emptyColumnMessage = (columnName: string): { title: string; detail: string } => ({
  title: `${columnName} is clear`,
  detail: "Tickets will settle here when work reaches this stage."
});

// Markdown audit: create-ticket drafts, ticket detail bodies, clarification text,
// and generated Codex completion/final-response console events use MarkdownBlock.
// Board excerpts and command output stay plain text because they are summaries/logs.
const copyToast = (kind: "markdown" | "code"): Toast => ({
  kind: "success",
  message: kind === "code" ? "Code copied." : "Markdown source copied."
});

const generateTicketSuggestionsOnce = (projectPath: string): ReturnType<RelayApi["ticket"]["generateSuggestions"]> => {
  const existing = ticketSuggestionRequests.get(projectPath);
  if (existing) return existing;

  const request = getRelayApi()
    .ticket.generateSuggestions(projectPath)
    .finally(() => {
      if (ticketSuggestionRequests.get(projectPath) === request) {
        ticketSuggestionRequests.delete(projectPath);
      }
    });
  ticketSuggestionRequests.set(projectPath, request);
  return request;
};

export function ProjectSidebar({
  projects,
  selectedPath,
  loading,
  onAdd,
  onSelect,
  onRemove,
  onReveal,
  defaultExpandedProjectPaths = []
}: {
  projects: ProjectSummary[];
  selectedPath: string | null;
  loading: boolean;
  onAdd: () => void;
  onSelect: (projectPath: string) => void;
  onRemove: (projectPath: string) => void;
  onReveal: (projectPath: string) => void;
  defaultExpandedProjectPaths?: string[];
}): ReactElement {
  const [expandedProjectPaths, setExpandedProjectPaths] = useState<Set<string>>(
    () => new Set([...defaultExpandedProjectPaths, ...(selectedPath ? [selectedPath] : [])])
  );

  useEffect(() => {
    if (!selectedPath) return;
    setExpandedProjectPaths((current) => {
      if (current.has(selectedPath)) return current;
      const next = new Set(current);
      next.add(selectedPath);
      return next;
    });
  }, [selectedPath]);

  const handleProjectClick = useCallback(
    (projectPath: string): void => {
      onSelect(projectPath);
      setExpandedProjectPaths((current) => {
        const next = new Set(current);
        if (selectedPath === projectPath && next.has(projectPath)) {
          next.delete(projectPath);
        } else {
          next.add(projectPath);
        }
        return next;
      });
    },
    [onSelect, selectedPath]
  );

  return (
    <aside className="sidebar" aria-label="Projects">
      <div className="sidebar-heading">
        <span>Projects</span>
        <button className="sidebar-icon-button" onClick={onAdd} disabled={loading} aria-label="Add project">
          {loading ? <Loader2 className="spin" size={16} /> : <FolderPlus size={16} />}
        </button>
      </div>

      <div className="sidebar-list" role="list">
        {projects.map((project, index) => {
          const expanded = expandedProjectPaths.has(project.path);
          const swimlaneListId = projectDisclosureTargetId(project, index);
          const ProjectFolderIcon = expanded ? FolderOpen : Folder;
          const projectActiveLabel = project.activeRunCount > 0 ? `, ${activeTaskCountLabel(project.activeRunCount)}` : "";
          return (
            <div className="project-group" key={project.path} role="listitem">
              <button
                type="button"
                className={clsx("project-folder-row", selectedPath === project.path && "selected", expanded && "expanded")}
                onClick={() => handleProjectClick(project.path)}
                aria-current={selectedPath === project.path ? "page" : undefined}
                aria-expanded={expanded}
                aria-controls={swimlaneListId}
                aria-label={`${expanded ? "Collapse" : "Expand"} ${project.name} swimlanes${projectActiveLabel}`}
              >
                <ProjectFolderIcon className="project-folder-icon" size={18} aria-hidden="true" />
                <span className="project-folder-name" title={project.name}>
                  {project.name}
                </span>
                <span className="project-folder-status" aria-hidden="true">
                  {project.health !== "ok" && <AlertTriangle size={13} />}
                  {project.activeRunCount > 0 && (
                    <span className="project-folder-active" title={activeTaskCountLabel(project.activeRunCount)}>
                      <CircleDashed size={13} />
                    </span>
                  )}
                </span>
              </button>
              {expanded && (
                <div id={swimlaneListId} className="project-swimlane-list" role="list" aria-label={`${project.name} swimlanes`}>
                  {project.swimlanes.length > 0 ? (
                    project.swimlanes.map((swimlane) => {
                      const hasActiveRun = swimlane.activeRunCount > 0;
                      const activeLabel = hasActiveRun ? `, ${activeTaskCountLabel(swimlane.activeRunCount)}` : "";
                      return (
                        <div
                          className={clsx("project-swimlane-row", hasActiveRun && "active")}
                          key={swimlane.id}
                          role="listitem"
                          aria-label={`${swimlane.name}: ${taskCountLabel(swimlane.ticketCount)}${activeLabel}`}
                        >
                          <span className="project-swimlane-name" title={swimlane.name}>
                            {swimlane.name}
                          </span>
                          <span className="project-swimlane-meta">
                            {hasActiveRun && (
                              <span className="project-swimlane-active" title={activeTaskCountLabel(swimlane.activeRunCount)} aria-hidden="true">
                                <Loader2 className="spin" size={12} />
                              </span>
                            )}
                            <span className="project-swimlane-count" aria-hidden="true">
                              {swimlane.ticketCount}
                            </span>
                          </span>
                        </div>
                      );
                    })
                  ) : (
                    <div className="project-swimlane-empty" role="listitem">
                      No swimlanes
                    </div>
                  )}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {selectedPath && (
        <div className="sidebar-actions">
          <button className="sidebar-action-button" onClick={() => onReveal(selectedPath)}>
            <ExternalLink size={15} />
            Reveal
          </button>
          <button className="sidebar-action-button" onClick={() => onRemove(selectedPath)}>
            <X size={15} />
            Remove
          </button>
        </div>
      )}
    </aside>
  );
}

function DroppableColumn({
  column,
  tickets,
  allTickets,
  columns,
  selectedTicketId,
  onOpen,
  onTicketFocus,
  onTicketButtonRef,
  now
}: {
  column: RelayColumn;
  tickets: TicketSummary[];
  allTickets: TicketSummary[];
  columns: RelayColumn[];
  selectedTicketId: string | null;
  onOpen: (ticketId: string) => void;
  onTicketFocus: (ticketId: string) => void;
  onTicketButtonRef: (ticketId: string, node: HTMLButtonElement | null) => void;
  now: number;
}): ReactElement {
  const { setNodeRef, isOver } = useDroppable({ id: column.id });
  const emptyMessage = emptyColumnMessage(column.name);
  return (
    <section ref={setNodeRef} className={clsx("board-column", isOver && "over")}>
      <header className="column-header">
        <h2>{column.name}</h2>
        <span>{tickets.length}</span>
      </header>
      <div className="column-body">
        {tickets.map((ticket) => (
          <DraggableCard
            key={ticket.id}
            ticket={ticket}
            allTickets={allTickets}
            columns={columns}
            selected={ticket.id === selectedTicketId}
            onOpen={onOpen}
            onFocus={onTicketFocus}
            onTicketButtonRef={onTicketButtonRef}
            now={now}
          />
        ))}
        {tickets.length === 0 && (
          <div className="empty-column">
            <span>{emptyMessage.title}</span>
            <p>{emptyMessage.detail}</p>
          </div>
        )}
      </div>
    </section>
  );
}

export function TicketCardContent({
  ticket,
  allTickets,
  columns,
  now
}: {
  ticket: TicketSummary;
  allTickets: TicketSummary[];
  columns: RelayColumn[];
  now: number;
}): ReactElement {
  const visibleLabels = ticket.labels.slice(0, 2);
  const hiddenLabelCount = ticket.labels.length - visibleLabels.length;
  const showPriority = ticket.priority === "high" || ticket.priority === "urgent";
  const showRunStatus = ticket.runStatus !== "idle";
  const elapsedLabel = activeRunElapsedLabel(ticket, now);
  const showRelationship = ticket.ticketType === "epic" || Boolean(ticket.parentEpicId);
  const blockerState = useMemo(() => resolveTicketBlockers(ticket, allTickets, columns), [allTickets, columns, ticket]);
  const showBlockerState = blockerState.isBlocked || blockerState.warnings.length > 0;

  return (
    <>
      <div className="card-title">{ticket.title}</div>
      <p className="card-excerpt">{ticket.excerpt || "No details yet."}</p>
      {(showRelationship || showPriority || showRunStatus || showBlockerState || elapsedLabel) && (
        <div className="card-meta">
          {ticket.ticketType === "epic" && <span className="ticket-type-pill epic">Epic</span>}
          {ticket.parentEpicId && <span className="ticket-type-pill subticket">Subticket</span>}
          {blockerState.isBlocked && (
            <span className="ticket-blocker-pill active" title={blockerState.activeBlockers.map(resolvedBlockerLabel).join("; ")}>
              Blocked
            </span>
          )}
          {blockerState.warnings.length > 0 && (
            <span className="ticket-blocker-pill warning" title={blockerState.warnings.join(" ")}>
              Blocker Warning
            </span>
          )}
          {showPriority && <span className={clsx("priority", ticket.priority)}>{ticket.priority}</span>}
          {showRunStatus && <TicketRunStatusPill status={ticket.runStatus} />}
          {elapsedLabel && <TicketRunElapsedPill label={elapsedLabel} />}
        </div>
      )}
      {visibleLabels.length > 0 && (
        <div className="labels">
          {visibleLabels.map((label) => (
            <span key={label}>{label}</span>
          ))}
          {hiddenLabelCount > 0 && <span className="label-overflow">+{hiddenLabelCount}</span>}
        </div>
      )}
    </>
  );
}

function DraggableCard({
  ticket,
  allTickets,
  columns,
  selected,
  onOpen,
  onFocus,
  onTicketButtonRef,
  now
}: {
  ticket: TicketSummary;
  allTickets: TicketSummary[];
  columns: RelayColumn[];
  selected: boolean;
  onOpen: (ticketId: string) => void;
  onFocus: (ticketId: string) => void;
  onTicketButtonRef: (ticketId: string, node: HTMLButtonElement | null) => void;
  now: number;
}): ReactElement {
  const { attributes, listeners, setNodeRef, transform, isDragging } = useDraggable({ id: ticket.id });
  const dragTransform = transform ? CSS.Translate.toString(transform) : null;
  const style = dragTransform ? { transform: dragTransform } : undefined;
  return (
    <article ref={setNodeRef} style={style} className={clsx("ticket-card", isDragging && "dragging", selected && "keyboard-selected")}>
      <button
        ref={(node) => onTicketButtonRef(ticket.id, node)}
        className="card-open"
        data-ticket-id={ticket.id}
        onClick={() => onOpen(ticket.id)}
        onFocus={() => onFocus(ticket.id)}
      >
        <TicketCardContent ticket={ticket} allTickets={allTickets} columns={columns} now={now} />
      </button>
      <button className="drag-handle" {...listeners} {...attributes} aria-label={`Drag ${ticket.title}`}>
        <CircleDashed size={16} />
      </button>
    </article>
  );
}

function BoardView({
  board,
  query,
  ticketNavigationEnabled,
  onQuery,
  onCreate,
  onGenerateTickets,
  onOpenTicket,
  onMove,
  gitMetadata
}: {
  board: BoardSnapshot;
  query: string;
  ticketNavigationEnabled: boolean;

  scroll-padding: 20px;
  transition:
    opacity 180ms var(--relay-ease),
    filter 180ms var(--relay-ease);
}

.board:focus-visible {
  outline: none;
  box-shadow: var(--relay-focus-ring);
}

.board-column {
  min-height: 0;
  border: 0;
  border-radius: var(--relay-radius-md);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 4.2%) 0%, rgb(255 255 255 / 1.8%) 100%),
    color-mix(in srgb, var(--relay-surface) 76%, transparent);
  display: flex;
  flex-direction: column;
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%),
    0 18px 48px rgb(0 0 0 / 18%);
  backdrop-filter: blur(12px);
  transition:
    background-color 180ms var(--relay-ease),
    box-shadow 180ms var(--relay-ease),
    transform 180ms var(--relay-spring);
}

.board-column.over {
  transform: translateY(-2px);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px color-mix(in srgb, var(--relay-primary) 34%, transparent),
    0 24px 70px rgb(0 0 0 / 30%);
}

.column-header {
  min-height: 48px;
  padding: 13px 14px 8px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.column-header h2 {
  margin: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-size: var(--relay-text-base);
  font-weight: 560;
  color: rgb(255 255 255 / 74%);
}

.column-header span {
  min-width: 24px;
  height: 22px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5%);
  color: var(--relay-text-muted);
  display: grid;
  place-items: center;
  font-size: var(--relay-text-sm);
}

.column-body {
  min-height: 0;
  overflow-y: auto;
  padding: 8px 12px 14px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.empty-column {
  min-height: 118px;
  border: 0;
  border-radius: var(--relay-radius-md);
  color: var(--relay-text-subtle);
  display: grid;
  place-items: center;
  align-content: center;
  gap: 5px;
  font-size: var(--relay-text-md);
  padding: 18px 16px;
  text-align: center;
  background:
    linear-gradient(180deg, rgb(255 255 255 / 3.5%), transparent),
    rgb(255 255 255 / 2.5%);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
  transition:
    background-color 180ms var(--relay-ease),
    box-shadow 180ms var(--relay-ease);
}

.empty-column span {
  color: var(--relay-text-muted);
  font-weight: 520;
}

.empty-column p {
  max-width: 220px;
  margin: 0;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
  line-height: 1.45;
}

.ticket-card {
  position: relative;
  border: 1px solid var(--relay-border-strong);
  border-radius: var(--relay-radius-md);
  background: var(--relay-surface-2);
  box-shadow: none;
  transition:
    opacity 180ms var(--relay-ease),
    filter 180ms var(--relay-ease),
    border-color 180ms var(--relay-ease);
}

.ticket-card:hover {
  background: var(--relay-surface-2);
  border-color: var(--relay-border-strong);
  box-shadow: none;
}

.ticket-card.keyboard-selected {
  background: var(--relay-surface-2);
  border-color: color-mix(in srgb, var(--relay-primary) 58%, var(--relay-border-strong));
  box-shadow: none;
}

.ticket-card:focus-within {
  border-color: color-mix(in srgb, var(--relay-ring) 64%, var(--relay-border-strong));
  box-shadow: none;
}

.board.board-has-focus .ticket-card:not(.keyboard-selected) {
  filter: saturate(0.72);
  opacity: 0.56;
}

.ticket-card.dragging {
  z-index: 10;
  opacity: 0.92;
  border-color: color-mix(in srgb, var(--relay-primary) 64%, var(--relay-border-strong));
  box-shadow: none;
}

.card-open {
  width: 100%;
  min-height: 0;
  display: block;
  text-align: left;
  border: 0;
  background: transparent;
  padding: 14px 42px 14px 14px;
  box-shadow: none;
  transition: none;
}

.card-open:hover {
  background: transparent;
  box-shadow: none;
  transform: none;
}

.card-open:active {
  background: transparent;
  box-shadow: none;
  transform: none;
}

.card-open:focus-visible {
  background: transparent;
  box-shadow: none;
}

.card-title {
  margin-bottom: 8px;
  color: var(--relay-text);
  font-weight: 560;
  line-height: 1.32;
}

.card-excerpt {
  display: -webkit-box;
  overflow: hidden;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 4;
  margin: 0;
  color: rgb(255 255 255 / 66%);
  font-size: var(--relay-text-md);
  line-height: 1.5;
}

.card-meta,
.labels,
.danger-row,
.detail-actions {
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.card-meta {
  margin-top: 12px;
  opacity: 0.82;
}

.priority,
.run-pill,
.run-elapsed-pill,
.ticket-type-pill,
.ticket-blocker-pill,
.labels span {
  min-height: 21px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5.5%);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
}

.run-pill,
.run-elapsed-pill {
  gap: 5px;
}

.run-elapsed-pill {
  flex: 0 0 auto;
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}

.run-pill-icon {
  flex: 0 0 auto;
}

.git-metadata {
  min-width: 0;
  max-width: min(100%, 360px);
  min-height: 22px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5%);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
  white-space: nowrap;
}

.git-metadata svg {
  flex: 0 0 auto;
}

.git-metadata > span {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
}

.git-metadata.compact {
  max-width: 170px;
  padding-inline: 6px;
}

.git-metadata.git-loading {
  color: var(--relay-text-subtle);
}

.git-metadata.git-ready {
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.git-metadata.git-ready.dirty {
  background: var(--relay-warning-muted);
  color: var(--relay-warning-text);
}

.git-metadata.git-not_git,
.git-metadata.git-missing {
  background: color-mix(in srgb, var(--relay-surface-2) 70%, transparent);
  color: var(--relay-text-subtle);
}

.git-metadata.git-unavailable,
.git-metadata.git-error {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.priority.high,
.priority.urgent {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.priority.low {
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.ticket-type-pill.epic {
  background: var(--relay-info-muted);
  color: var(--relay-info-text);
}

.ticket-type-pill.subticket,
.ticket-type-pill.task {
  background: rgb(255 255 255 / 5.5%);
  color: var(--relay-text-muted);
}

.ticket-blocker-pill.active {
  background: var(--relay-warning-muted);
  color: var(--relay-warning-text);
  box-shadow: inset 0 0 0 1px color-mix(in srgb, var(--relay-warning) 18%, transparent);
}

.ticket-blocker-pill.warning {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.run-pill.queued,
.run-pill.running,
.run-pill.blocked,
.run-pill.drafting,
.run-elapsed-pill {
  background: var(--relay-warning-muted);
  color: var(--relay-warning-text);
  box-shadow: inset 0 0 0 1px color-mix(in srgb, var(--relay-warning) 18%, transparent);
}

.run-pill.completed,
.run-pill.draft_complete {
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.run-pill.failed,
.run-pill.cancelled,
.run-pill.draft_failed {

import test from "node:test";
import assert from "node:assert/strict";
import { renderToStaticMarkup } from "react-dom/server";
import {
  activeRunElapsedLabel,
  DraftingTicketDetailLoading,
  TicketCardContent,
  TicketSuggestionsModalContent,
  TicketRunElapsedPill,
  TicketRunStatusPill
} from "../src/renderer/src/App";
import { DEFAULT_COLUMNS, type TicketSuggestion, type TicketSummary } from "../src/shared/types";

const ticketSummary = (patch: Partial<TicketSummary> = {}): TicketSummary => ({
  schemaVersion: 1,
  id: "tkt_elapsed",
  title: "Elapsed runtime",
  ticketType: "task",
  status: "in_progress",
  position: 1000,
  priority: "medium",
  labels: [],
  parentEpicId: null,
  subticketIds: [],
  blockedByIds: [],
  createdAt: "2026-05-12T10:00:00.000Z",
  updatedAt: "2026-05-12T10:00:00.000Z",
  codexThreadId: null,
  runStatus: "running",
  lastRunId: "run_elapsed",
  lastRunStartedAt: "2026-05-12T10:00:00.000Z",
  excerpt: "Runtime card",
  filePath: "/tmp/tkt_elapsed.md",
  ...patch
});

test("drafting ticket status pill renders an active spinner indicator", () => {
  const markup = renderToStaticMarkup(<TicketRunStatusPill status="drafting" />);

  assert.match(markup, /run-pill drafting/);
  assert.match(markup, /spin run-pill-icon/);
  assert.match(markup, /Drafting/);
});

test("in-progress running ticket elapsed pill renders compact runtime", () => {
  const ticket = ticketSummary();
  const now = Date.parse("2026-05-12T10:01:05.000Z");
  const label = activeRunElapsedLabel(ticket, now);

  assert.equal(label, "01:05");
  if (!label) assert.fail("Expected an elapsed label.");
  const markup = renderToStaticMarkup(<TicketRunElapsedPill label={label} />);
  assert.match(markup, /run-elapsed-pill/);
  assert.match(markup, /Agent running for 01:05/);
  assert.match(markup, />01:05</);

  const cardMarkup = renderToStaticMarkup(<TicketCardContent ticket={ticket} allTickets={[ticket]} columns={DEFAULT_COLUMNS} now={now} />);
  assert.match(cardMarkup, /card-meta/);
  assert.match(cardMarkup, /run-pill running/);
  assert.match(cardMarkup, /Running/);
  assert.match(cardMarkup, /run-elapsed-pill/);
  assert.match(cardMarkup, /Agent running for 01:05/);
  assert.match(cardMarkup, />01:05</);
});

test("elapsed runtime label is hidden outside active in-progress implementation runs", () => {
  const now = Date.parse("2026-05-12T10:01:05.000Z");

  for (const ticket of [
    ticketSummary({ status: "ready" }),
    ticketSummary({ runStatus: "queued" }),
    ticketSummary({ runStatus: "blocked" }),
    ticketSummary({ runStatus: "completed" }),
    ticketSummary({ lastRunStartedAt: null }),
    ticketSummary({ lastRunStartedAt: "not-a-date" })
  ]) {
    assert.equal(activeRunElapsedLabel(ticket, now), null);
