231	export const activeRunElapsedLabel = (
232	  ticket: Pick<TicketSummary, "status" | "runStatus" | "lastRunStartedAt">,
233	  now: number
234	): string | null => {
235	  if (ticket.status !== RELAY_IN_PROGRESS_STATUS || ticket.runStatus !== "running" || !ticket.lastRunStartedAt) return null;
236	  const startedAt = Date.parse(ticket.lastRunStartedAt);
237	  if (Number.isNaN(startedAt)) return null;
238	  const elapsedMs = now - startedAt;
239	  if (!Number.isFinite(elapsedMs)) return null;
240	  return formatElapsedDuration(elapsedMs);
241	};
